export class PublisherResource{constructor(e,r){this.references=new Map,this.publisher=e,this.name=r}addReference(e,r,s){let t=this.publisher.resolveLanguage(e);this.references.has(r)||this.references.set(r,new Map);let n=this.references.get(r);n.has(s)||n.set(s,new Set);let a=n.get(s);if(a.has(t))throw Error(`duplicate reference: language "${e}" already has text "${s}" for reference "${r}"`);a.add(t)}getEntries(){return[...this.references.entries()].map(([e,r])=>({resource:this.name,reference:e,sources:Object.fromEntries([...r.entries()].map(([e,r])=>[e,[...r]]))}))}}